export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

const DEFAULT_DELIMITER = ',';
const DEFAULT_QUOTE = '"';
const DEFAULT_LINE_SEPARATOR = '\n';

const NUMERIC_REGEX = /^[+-]?(?:\d+\.?\d*|\.\d+)(?:[eE][+-]?\d+)?$/;

function coerceValue(value: string): unknown {
  const trimmed = value.trim();
  if (trimmed === '' || trimmed.toLowerCase() === 'null') {
    return null;
  }

  const lower = trimmed.toLowerCase();
  if (lower === 'true') {
    return true;
  }
  if (lower === 'false') {
    return false;
  }

  if (NUMERIC_REGEX.test(trimmed)) {
    const num = Number(trimmed);
    if (!Number.isNaN(num)) {
      return num;
    }
  }

  return trimmed;
}

function createResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  const result: CSVResult = {
    rows,
    headers,
    errors,
    filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult {
      const filteredRows = rows.filter(predicate);
      return createResult(filteredRows, headers, errors);
    },
    sum(column: string): number {
      return rows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          return acc + value;
        }
        return acc;
      }, 0);
    },
    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count(): number {
      return rows.length;
    },
    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };
  return result;
}

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter && options.delimiter.length > 0 ? options.delimiter : DEFAULT_DELIMITER;
  const quote = options?.quote && options.quote.length > 0 ? options.quote[0] : DEFAULT_QUOTE;
  const customLineSeparator = options?.lineSeparator;
  const useCustomSeparator = typeof customLineSeparator === 'string' && customLineSeparator.length > 0;
  const lineSeparator = useCustomSeparator ? customLineSeparator : DEFAULT_LINE_SEPARATOR;

  const rowsMeta: { values: string[]; rowNumber: number }[] = [];
  const errors: CSVError[] = [];

  let currentRow: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let currentRowNumber = 1;
  let seenCharacter = false;

  const flushField = () => {
    currentRow.push(currentField);
    currentField = '';
  };

  const flushRow = () => {
    flushField();
    rowsMeta.push({ values: currentRow, rowNumber: currentRowNumber });
    currentRow = [];
    currentRowNumber += 1;
  };

  const matchLineSeparator = (idx: number): { matched: boolean; length: number } => {
    if (useCustomSeparator) {
      if (input.substr(idx, lineSeparator.length) === lineSeparator) {
        return { matched: true, length: lineSeparator.length };
      }
      return { matched: false, length: 0 };
    }
    const char = input[idx];
    if (char === '\r') {
      if (input[idx + 1] === '\n') {
        return { matched: true, length: 2 };
      }
      return { matched: true, length: 1 };
    }
    if (char === '\n') {
      return { matched: true, length: 1 };
    }
    return { matched: false, length: 0 };
  };

  for (let i = 0; i < input.length; i += 1) {
    const char = input[i];
    seenCharacter = true;

    if (!inQuotes) {
      const separatorCheck = matchLineSeparator(i);
      if (separatorCheck.matched) {
        flushRow();
        i += separatorCheck.length - 1;
        continue;
      }

      if (delimiter.length > 0 && input.substr(i, delimiter.length) === delimiter) {
        flushField();
        i += delimiter.length - 1;
        continue;
      }
    }

    if (char === quote) {
      if (inQuotes && input[i + 1] === quote) {
        currentField += quote;
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    currentField += char;
  }

  if (inQuotes) {
    errors.push({ row: currentRowNumber, message: 'Unterminated quoted field detected' });
    // drop partial row and do not add incomplete row
  } else if (seenCharacter || currentRow.length > 0 || currentField.length > 0) {
    flushRow();
  }

  if (rowsMeta.length === 0) {
    return createResult([], [], errors);
  }

  const headerMeta = rowsMeta[0];
  const headers = headerMeta.values.map((value) => value);
  const dataRows: Record<string, unknown>[] = [];

  for (let idx = 1; idx < rowsMeta.length; idx += 1) {
    const meta = rowsMeta[idx];
    if (meta.values.length !== headers.length) {
      errors.push({
        row: meta.rowNumber,
        message: `Malformed row: expected ${headers.length} columns but found ${meta.values.length}`,
      });
      continue;
    }

    const record: Record<string, unknown> = {};
    for (let col = 0; col < headers.length; col += 1) {
      record[headers[col]] = coerceValue(meta.values[col]);
    }
    dataRows.push(record);
  }

  return createResult(dataRows, headers, errors);
}
