cat <<'EOF' > csv-parser.test.ts
import { parseCSV } from './csv-parser';

function assert(condition: boolean, message?: string): void {
  if (!condition) {
    throw new Error(message || 'Assertion failed');
  }
}

function testBasicParsing(): void {
  const csv = 'name,age\nAlice,30\nBob,25';
  const result = parseCSV(csv);
  assert(result.headers.length === 2, 'Expected two headers');
  assert(result.headers[0] === 'name');
  assert(result.rows.length === 2, 'Expected two rows');
  assert(result.rows[0].name === 'Alice');
  assert(result.rows[0].age === 30);
  assert(result.rows[1].name === 'Bob');
  assert(result.rows[1].age === 25);
}

function testQuotedFields(): void {
  const csv = 'id,note\n1,"hello, world"\n2,"goodbye"';
  const result = parseCSV(csv);
  assert(result.rows.length === 2);
  assert(result.rows[0].note === 'hello, world');
  assert(result.rows[1].note === 'goodbye');
}

function testEscapedQuotes(): void {
  const csv = 'message\n"She said ""Hello"""';
  const result = parseCSV(csv);
  assert(result.rows.length === 1);
  assert(result.rows[0].message === 'She said "Hello"');
}

function testCustomDelimitersAndSeparators(): void {
  const csv = "name;role||'Jane Doe';'Lead, Developer'||'Sam';'Tester'";
  const result = parseCSV(csv, { delimiter: ';', quote: "'", lineSeparator: '||' });
  assert(result.headers.length === 2);
  assert(result.rows.length === 2);
  assert(result.rows[0].name === 'Jane Doe');
  assert(result.rows[0].role === 'Lead, Developer');
  assert(result.rows[1].name === 'Sam');
  assert(result.rows[1].role === 'Tester');
}

function testTypeCoercion(): void {
  const csv = 'intVal,floatVal,boolTrue,boolFalse,nullLower,nullUpper,emptyVal,stringVal\n1,2.5,true,FALSE,null,NULL,,hello';
  const result = parseCSV(csv);
  assert(result.rows.length === 1);
  const row = result.rows[0];
  assert(row.intVal === 1);
  assert(row.floatVal === 2.5);
  assert(row.boolTrue === true);
  assert(row.boolFalse === false);
  assert(row.nullLower === null);
  assert(row.nullUpper === null);
  assert(row.emptyVal === null);
  assert(row.stringVal === 'hello');
}

function testMalformedRowErrorCollection(): void {
  const csv = 'a,b\n1,2\n3';
  const result = parseCSV(csv);
  assert(result.rows.length === 1);
  assert(result.errors.length === 1);
  assert(result.errors[0].row === 3);
  assert(result.errors[0].message.includes('expected 2 columns'));
}

function testFilterFunctionality(): void {
  const csv = 'name,age\nAlice,30\nBob,40\nCharlie,25';
  const parsed = parseCSV(csv);
  const filtered = parsed.filter((row) => typeof row.age === 'number' && row.age >= 30);
  assert(filtered.rows.length === 2);
  assert(filtered.rows.every((row) => (row.age as number) >= 30));
  assert(parsed.rows.length === 3, 'Original result should remain unchanged');
}

function testAggregationMethods(): void {
  const csv = 'group,value\nA,10\nA,20\nB,5\nB,5\nC,invalid';
  const result = parseCSV(csv);
  assert(result.count() === 5);
  assert(result.sum('value') === 40, 'Sum should only include numeric values');
  assert(result.average('value') === 10);
  const grouped = result.groupBy('group');
  assert(grouped.size === 3);
  assert(grouped.get('A')?.length === 2);
  assert(grouped.get('B')?.length === 2);
  assert(grouped.get('C')?.length === 1);
}

function testEdgeCases(): void {
  const empty = parseCSV('');
  assert(empty.rows.length === 0);
  assert(empty.headers.length === 0);
  assert(empty.errors.length === 0);
  assert(empty.count() === 0);
  assert(empty.sum('anything') === 0);
  assert(empty.groupBy('anything').size === 0);

  const singleColumn = parseCSV('only\nvalue');
  assert(singleColumn.headers.length === 1);
  assert(singleColumn.rows.length === 1);
  assert(singleColumn.rows[0].only === 'value');

  const singleRow = parseCSV('col1,col2\nvalue1,value2');
  assert(singleRow.rows.length === 1);
  assert(singleRow.rows[0].col1 === 'value1');
  assert(singleRow.rows[0].col2 === 'value2');

  const largeField = 'col\n"' + 'X'.repeat(12000) + '"';
  const largeResult = parseCSV(largeField);
  assert(largeResult.rows.length === 1);
  assert(typeof largeResult.rows[0].col === 'string');
  assert((largeResult.rows[0].col as string).length === 12000);
}

function runTests(): void {
  testBasicParsing();
  testQuotedFields();
  testEscapedQuotes();
  testCustomDelimitersAndSeparators();
  testTypeCoercion();
  testMalformedRowErrorCollection();
  testFilterFunctionality();
  testAggregationMethods();
  testEdgeCases();
  console.log('All csv-parser tests passed');
}

runTests();
